INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'trmte8s',
  'band shrug',
  'Encogimiento de hombros con banda',
  'https://static.exercisedb.dev/media/trmte8s.gif',
  'neck',
  'band',
  'traps',
  ARRAY['shoulders']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros y coloca la banda debajo de tus pies, sosteniendo los extremos con tus manos.', 'Paso 2: mantén tus brazos rectos y relajado, y deja la banda cuelga frente a tus muslos.', 'Paso 3: activa tus traps encogiendo los hombros tus hombros hacia arriba, levantando la banda lo más alto posible.', 'Paso 4: sostén el contracción por a momento, luego baja lentamente tus hombros espalda abajo a la posición inicial.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'traps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
