  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'UFGF6gk',
  'cable rope crossover seated row',
  'En Polea En Cuerda Crossover Remo Sentado',
  'https://static.exercisedb.dev/media/UFGF6gk.gif',
  'back',
  'cable',
  'upper back',
  ARRAY['biceps', 'forearms']::text[],
  ARRAY['Paso 1: siéntate en rowing máquina con tus pies plano en el footrests y tus rodillas ligeramente doblado.', 'Paso 2: agarra el cable ropes con un prono agarra, palmas mirando hacia cada otro.', 'Paso 3: inclínate espalda ligeramente, manteniendo tus espalda rectos y tu core engaged.', 'Paso 4: jala el cable ropes hacia tu pecho, apretando tu hombro blades together.', 'Paso 5: haz una pausa breve en el peak del movimiento, luego lentamente release el tensión y regresa a la posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'back' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
  gif_url          = EXCLUDED.gif_url,
  body_part        = EXCLUDED.body_part,
  equipment        = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
