  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: siéntate en un ejercicio ball con tus pies plano en el suelo y tu espalda recto.', 'Paso 2: sostén una mancuerna en cada mano con tus palmas mirando hacia tu cuerpo y tus brazos completamente extendido.', 'Paso 3: manteniendo tus superior brazos fijo, exhala y curl one dumbbell arriba hacia tu hombro while manteniendo tus palma mirando hacia tu cuerpo.', 'Paso 4: continúa a raise la mancuerna hasta tus bíceps completamente contraído y la mancuerna en hombro level.', 'Paso 5: sostén el contracted posición por a brief haz una pausa as aprieta tus biceps.', 'Paso 6: inhala y baja lentamente la mancuerna espalda a la posición inicial.', 'Paso 7: repite el movimiento con el opuesto brazo.', 'Paso 8: continúa alternando brazos por el desired number de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
