  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'aWedzZX',
  'glute bridge two legs on bench (male)',
  'Puente De GlúTeos Two Legs On Bench (Male)',
  'https://static.exercisedb.dev/media/aWedzZX.gif',
  'upper legs',
  'body weight',
  'glutes',
  ARRAY['hamstrings', 'core']::text[],
  ARRAY['Paso 1: siéntate en edge de un banco con tu espalda contra y tus pies plano en el suelo.', 'Paso 2: coloca tus manos en el banco beside tus caderas por support.', 'Paso 3: activa tus glutes y hamstrings, luego levanta tus caderas lejos del banco hasta tu cuerpo forms a recto línea desde tus rodillas a tus hombros.', 'Paso 4: haz una pausa breve en el punto más alto, luego baja lentamente tus caderas espalda abajo a la posición inicial.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'glutes' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
  gif_url          = EXCLUDED.gif_url,
  body_part        = EXCLUDED.body_part,
  equipment        = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

