  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'ZgsNQ6d',
  'inchworm',
  'Inchworm',
  'https://static.exercisedb.dev/media/ZgsNQ6d.gif',
  'waist',
  'body weight',
  'abs',
  ARRAY['shoulders', 'hamstrings']::text[],
  ARRAY['Paso 1: comienza de pie con tus pies al ancho de las caderas.', 'Paso 2: dobla hacia adelante en el cintura y coloca tus manos en el suelo frente a .', 'Paso 3: camina tus manos hacia adelante hasta en un alto plank posición, con tu cuerpo en un recto línea desde cabeza a dedo del pie.', 'Paso 4: haz una pausa breve, luego camina tus manos espalda hacia tus pies, manteniendo tus piernas as recto as possible.', 'Paso 5: una vez tus manos reach tus pies, stand espalda arriba a la posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
  gif_url          = EXCLUDED.gif_url,
  body_part        = EXCLUDED.body_part,
  equipment        = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

INSERT INTO exercises (
