  'Con Barra Inverso Grip Remo Inclinado',
  'https://static.exercisedb.dev/media/SzX3uzM.gif',
  'back',
  'barbell',
  'upper back',
  ARRAY['biceps', 'forearms']::text[],
  ARRAY['Paso 1: párate con los pies al ancho de los hombros y rodillas ligeramente doblado.', 'Paso 2: sostén una barra con un prono agarra, palmas mirando hacia abajo, y manos ligeramente wider than al ancho de los hombros.', 'Paso 3: dobla hacia adelante en el caderas, manteniendo tus espalda rectos y pecho arriba, hasta tu torso almost paralelo al suelo.', 'Paso 4: jala la barra hacia tus inferior pecho, apretando tu hombro blades together.', 'Paso 5: haz una pausa breve en el punto más alto, luego baja lentamente la barra espalda a la posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'back' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
