  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'hq2hyDH',
  'dumbbell standing preacher curl',
  'Con Mancuerna De Pie Curl En Predicador',
  'https://static.exercisedb.dev/media/hq2hyDH.gif',
  'upper arms',
  'dumbbell',
  'biceps',
  ARRAY['forearms']::text[],
  ARRAY['Paso 1: párate erguido con tus pies al ancho de los hombros y sostén una mancuerna en cada mano, palmas mirando hacia adelante.', 'Paso 2: Rest el espalda de tus brazos superiores contra el preacher banco o un incline banco, con tus codos ligeramente doblado.', 'Paso 3: manteniendo tus superior brazos fijo, exhala y curl el weights while contrayendo tus bíceps.', 'Paso 4: continúa a raise las mancuernas hasta tus bíceps completamente contraído y las mancuernas en hombro level.', 'Paso 5: sostén el contracted posición por a brief haz una pausa as aprieta tus biceps.', 'Paso 6: inhala y lentamente comienza a inferior las mancuernas espalda a la posición inicial.', 'Paso 7: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'biceps' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
  gif_url          = EXCLUDED.gif_url,
  body_part        = EXCLUDED.body_part,
  equipment        = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

