  ARRAY['Paso 1: Adjust el incline banco a a 30-45 degree ángulo.', 'Paso 2: siéntate en banco con una mancuerna en un mano, apoyado en tu muslo.', 'Paso 3: acuéstate en el banco, manteniendo tus pies planos en el suelo.', 'Paso 4: sostén la mancuerna con tu brazo extended recto arriba sobre tu pecho.', 'Paso 5: inferior la mancuerna out a la lado en un wide arc, manteniendo a leve dobla en tu codo.', 'Paso 6: haz una pausa cuando tu brazo paralelo al suelo, luego reverse el movimiento a lleva la mancuerna espalda a la posición inicial.', 'Paso 7: repite por el número deseado de repeticiones, luego cambia brazos.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
