  ARRAY['Paso 1: comienza en posición de empuja-arriba con tus manos ligeramente wider than al ancho de los hombros y tus pies al ancho de las caderas.', 'Paso 2: inferior tu cuerpo hacia el suelo, doblando tus codos y manteniendo tus core engaged.', 'Paso 3: mientras bajas tu cuerpo, shift tus weight espalda y levanta tus caderas arriba hacia el ceiling, creating un inverted V shape con tu cuerpo.', 'Paso 4: continúa a inferior tu cuerpo hasta tu pecho just sobre el suelo, luego reverse el movimiento, empujando tus caderas espalda abajo y extendiendo tus brazos a regresa a la posición inicial.', 'Paso 5: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'chest' LIMIT 1)
