  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'PKlXuJW',
  'rough band push sit-up',
  'Rough Con Banda Push Abdominal',
  'https://static.exercisedb.dev/media/PKlXuJW.gif',
  'waist',
  'band',
  'abs',
  ARRAY['shoulders', 'chest']::text[],
  ARRAY['Paso 1: fija la banda securely a a estable anchor point.', 'Paso 2: acuéstate plano en tu espalda con tus rodillas doblado y pies plano en el suelo.', 'Paso 3: sostén la banda con ambos manos y extiende tus brazos recto arriba hacia el ceiling. enfócate en rough movimiento.', 'Paso 4: activando tus abdominales, lentamente levanta tus superior cuerpo lejos del suelo, curling hacia adelante hasta tu torso en un 45-degree ángulo.', 'Paso 5: haz una pausa breve en el punto más alto, luego lentamente baja tus superior cuerpo espalda abajo a la posición inicial.', 'Paso 6: repite por el número deseado de repeticiones.']::text[],
  false,
  (SELECT id FROM muscle_groups WHERE slug = 'abs' LIMIT 1)
) ON CONFLICT (exercisedb_id) DO UPDATE SET
  name             = EXCLUDED.name,
  name_es          = EXCLUDED.name_es,
  gif_url          = EXCLUDED.gif_url,
  body_part        = EXCLUDED.body_part,
  equipment        = EXCLUDED.equipment,
  target_muscle    = EXCLUDED.target_muscle,
  secondary_muscles= EXCLUDED.secondary_muscles,
  instructions     = EXCLUDED.instructions,
  muscle_group_id  = EXCLUDED.muscle_group_id;

