  ARRAY['forearms']::text[],
  ARRAY['Paso 1: configura un incline banco en un 45-degree ángulo.', 'Paso 2: acuéstate boca abajo en el banco con tu pecho y abdomen apoyado contra .', 'Paso 3: sostén una barra con un supino agarra, al ancho de los hombros.', 'Paso 4: extiende tus brazos completamente, allowing la barra a cuelga abajo hacia el suelo.', 'Paso 5: manteniendo tus superior brazos fijo, exhala y curl el weights while contrayendo tus bíceps.', 'Paso 6: continúa a raise la barra hasta tus bíceps completamente contraído y la barra en hombro level.', 'Paso 7: (intensive variation) sostén el contracted posición por a brief haz una pausa as aprieta tus biceps.', 'Paso 8: inhala y lentamente comienza a inferior la barra espalda a la posición inicial.', 'Paso 9: repite por el número deseado de repeticiones.']::text[],
