INSERT INTO exercises (
  exercisedb_id, name, name_es,
  gif_url, body_part, equipment, target_muscle, secondary_muscles,
  instructions, is_custom, muscle_group_id
) VALUES (
  'pgIdT6i',
  'band one arm standing low row - lateral variation',
  'Con Banda One Arm De Pie Low Remo - Lateral Variation',
  'https://static.exercisedb.dev/media/pgIdT6i.gif',
  'back',
  'band',
  'upper back',
  ARRAY['biceps', 'shoulders']::text[],
  ARRAY['Paso 1: fija la banda a a estable anchor point en cintura altura.', 'Paso 2: párate frente a anchor point con tus pies al ancho de los hombros.', 'Paso 3: sostén la banda con un mano, palma mirando hacia adentro, y da un paso espalda a create tensión en la banda.', 'Paso 4: dobla tus rodillas ligeramente y hinge hacia adelante en el caderas, manteniendo tus espalda rectos.', 'Paso 5: jala la banda hacia tu cintura, apretando tu hombro blades together.', 'Paso 6: haz una pausa breve en el punto más alto del movimiento, luego lentamente release la banda espalda a la posición inicial.', 'Paso 7: repite por el número deseado de repeticiones, luego cambia lados. Emphasize lateral control.']::text[],
  false,
